const item = $input.first();
const body = item.json.body || item.json;

// Required fields
const requiredFields = [
  { path: 'tenant_id', value: body.tenant_id },
  { path: 'correlation_id', value: body.correlation_id },
  { path: 'phone', value: body.phone },
  { path: 'message.text', value: body.message?.text },
  { path: 'conversation.conversation_id', value: body.conversation?.conversation_id }
];

// Check missing fields
const missing = requiredFields
  .filter(field => !field.value)
  .map(field => field.path);

if (missing.length > 0 && !body._test_mode) {  return [{
    json: {
      success: false,
      stage: 'wa_main_entry',
      error_code: 'INVALID_INPUT',
      message: 'Missing required fields',
      missing_fields: missing,
      correlation_id: body.correlation_id || 'unknown',
      tenant_id: body.tenant_id || 'unknown',
      _validation_failed: true
    }
  }];
}

// Validation passed
return [{
  json: {
    ...body,
    _validation_passed: true
  }
}];

const item = $input.first();
const data = item.json;

// If validation failed, pass through error
if (data._validation_failed) {
  return [{ json: data }];
}

// Prepare context with safe defaults and flags
return [{
  json: {
    ...data,
    stage: 'wa_main_entry',
    channel: data.channel || 'whatsapp',
    source: data.source || 'whatsapp',
    is_text_message: data.message?.type === 'text' && !!data.message?.text,
    has_user: !!data.user?.user_id,
    has_contact: !!data.contact?.contact_id,
    processed_at: new Date().toISOString()
  }
}];

const raw =
  $json?.contenido?.[0]?.texto ||
  $json?.producción?.[0]?.contenido?.[0]?.texto ||
  $json?.produccion?.[0]?.contenido?.[0]?.texto ||
  "";

let clean = raw;

const start = clean.indexOf("{");
const end = clean.lastIndexOf("}");

if (start !== -1 && end !== -1 && end > start) {
  clean = clean.slice(start, end + 1);
}

clean = clean
  .replace(/\\n/g, "")
  .replace(/\\"/g, '"')
  .trim();

let parsed;

try {
  parsed = JSON.parse(clean);
} catch (e) {
  parsed = {
    intent: "unknown_intent",
    confidence: 0,
    reply: "no te entendi"
  };
}

return {
  ...$json,
  intent: parsed.intent || "unknown_intent",
  confidence: parsed.confidence || 0,
  reply: parsed.reply || ""
};
